mapper.select:
select a.application_id, a.user_id, u.nickname user_name, u.phone, u.email, a.apply_type, a.claimed_artist_id, a.artist_avatar_url, a.artist_cover_url, a.artist_name, a.gender, a.language, a.artist_bio, a.real_name, a.id_card, a.back, a.front, a.half_body, a.reviewed_by, a.rejection_reason, a.applied_at, a.reviewed_at, a.status from artist_application a left join user u on a.user_id = u.user_id
and u.nickname like concat('%',#{artistApplicationPageDTO.nickname},'%')
and u.phone like concat('%',#{artistApplicationPageDTO.phone},'%')
and u.email like concat('%',#{artistApplicationPageDTO.email},'%')
and a.apply_type = #{artistApplicationPageDTO.applyType}
and a.status = #{artistApplicationPageDTO.status}
